import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote — base premiums", () => {
    it.todo("should return base premium + processing fee for a single sword (new customer, first contract)");
    it.todo("should return correct base premium for an amulet");
    it.todo("should return correct base premium for a staff");
    it.todo("should return correct base premium for a potion");
    it.todo("should return correct base premium for a single component");
    it.todo("should return special rate for 3 alike components");
  });

  describe("Quote — surcharges and discounts", () => {
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for a highly enchanted item (enchantment >= 5)");
    it.todo("should give 20% loyalty discount for long-standing customers (>= 2 years)");
    it.todo("should add 10% initial assessment surcharge on first contract");
    it.todo("should give 15% discount on each contract after the first");
  });

  describe("Quote — multiple items", () => {
    it.todo("should sum premiums for multiple items and add a single processing fee");
  });

  describe("Claim — basic payout", () => {
    it.todo("should deduct 100 G deductible from damage amount");
    it.todo("should cap total payout at twice the insurance sum of the policy");
    it.todo("should reimburse at 50% for items with enchantment level >= 8");
    it.todo("should fully reimburse damage to items made of dragon material");
  });

  describe("Claim — remaining cap tracking", () => {
    it.todo("should track remaining cap after a claim and reduce it for subsequent claims");
  });
});

