    it.todo("should add 10% initial assessment surcharge on first contract");
    it.todo("should give 15% discount on each contract after the first");
  });

  describe("Quote — multiple items", () => {
    it.todo("should sum premiums for multiple items and add a single processing fee");
  });

  describe("Claim — basic payout", () => {
    it.todo("should deduct 100 G deductible from damage amount");
    it.todo("should cap total payout at twice the insurance sum of the policy");
    it.todo("should reimburse at 50% for items with enchantment level >= 8");
    it.todo("should fully reimburse damage to items made of dragon material");
  });

  describe("Claim — remaining cap tracking", () => {
    it.todo("should track remaining cap after a claim and reduce it for subsequent claims");
  });
});

